'use strict';(function(){const indexCfg={};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','parent'],};const index=FlexSearch.create(indexCfg);window.geekdocSearchIndex=index;index.add({'id':0,'href':'/','title':"Home",'parent':'','content':"Welcome to alexsalter.net\u0026hellip; are you lost?\n"});index.add({'id':1,'href':'/note/','title':"Notes",'parent':"Home",'content':""});index.add({'id':2,'href':'/note/debian/packages-third-party/','title':"Packages (third party)",'parent':"Debian",'content':"Azure CLI curl -sL https://packages.microsoft.com/keys/microsoft.asc \\  | gpg --dearmor \\  | tee /etc/apt/trusted.gpg.d/microsoft.gpg \u0026gt; /dev/null AZ_REPO=$(lsb_release -cs) echo \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/azure-cli/ $AZ_REPOmain\u0026#34; \\  | tee /etc/apt/sources.list.d/azure-cli.list apt update apt install azure-cli Docker curl -fsSL https://download.docker.com/linux/debian/gpg \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://download.docker.com/linux/debian $(lsb_release -cs)stable\u0026#34; apt update apt install docker-ce usermod -aG docker ${USER} su - ${USER} Disable zfs plugin in /etc/containerd/config.toml\ndisabled_plugins = [\u0026quot;cri\u0026quot;, \u0026quot;zfs\u0026quot;] GitHub CLI apt-key adv --keyserver keyserver.ubuntu.com --recv-key C99B11DEB97541F0 apt-add-repository https://cli.github.com/packages apt update apt install gh Helm curl https://baltocdn.com/helm/signing.asc \\ | apt-key add - echo \u0026quot;deb https://baltocdn.com/helm/stable/debian/ all main\u0026quot; \\ | tee /etc/apt/sources.list.d/helm-stable-debian.list apt-get update apt-get install helm Kubectl curl -s https://packages.cloud.google.com/apt/doc/apt-key.gpg \\  | apt-key add - echo \u0026#34;deb https://apt.kubernetes.io/ kubernetes-xenial main\u0026#34; \\  | tee -a /etc/apt/sources.list.d/kubernetes.list apt-get update apt-get install kubectl Microsoft .NET SDK wget https://packages.microsoft.com/config/debian/10/packages-microsoft-prod.deb \\  -O packages-microsoft-prod.deb dpkg -i packages-microsoft-prod.deb rm packages-microsoft-prod.deb apt-get update apt-get install -y dotnet-sdk-3.1 apt-get install -y dotnet-sdk-5.0 Visual Code apt update curl -sSL https://packages.microsoft.com/keys/microsoft.asc \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/vscode stable main\u0026#34; apt update apt install code "});index.add({'id':3,'href':'/note/debian/gnome-extensions/','title':"Gnome extensions",'parent':"Debian",'content':"Install the gnome-shell-extensions package.\napt update apt install gnome-shell-extensions Activate packages on https://extensions.gnome.org\n No top left hot corner Sound output device chooser Todo txt  "});index.add({'id':4,'href':'/note/debian/appearance/','title':"Appearance",'parent':"Debian",'content':"Change the theme to Adwaita-dark\ngsettings set org.gnome.desktop.interface gtk-theme \u0026#34;Adwaita-dark\u0026#34; "});index.add({'id':5,'href':'/note/debian/audioengine-hd3/','title':"Audioengine HD3",'parent':"Debian",'content':"The Audioengine HD3 speakers do not appear to support a sample rate of 44.1kHz which is the default.\nWe therefore need change the sample rate to 48kHz and restart pulseaudio.\nsed \\  -i \u0026#39;s/; default-sample-rate = 44100/default-sample-rate = 48000/g\u0026#39; \\  /etc/pulse/daemon.conf pulseaudio -k "});index.add({'id':6,'href':'/note/debian/packages/','title':"Packages",'parent':"Debian",'content':"Main    Name Description     bridge-utils Utilities for configuring the Linux Ethernet bridge   dnsutils Clients provided with BIND   gimp    git    htop interactive processes viewer   inkscape    hwinfo Hardware identification system   openssh-server    pavucontrol    tree displays an indented directory tree, in color    apt update apt install \\  apt-transport-https \\  bridge-utils \\  ca-certificates \\  curl \\  dnsutils \\  gimp \\  git \\  gnupg \\  gnupg2 \\  htop \\  hwinfo \\  inkscape \\  lsb-release \\  openssh-server \\  pavucontrol \\  software-properties-common \\  tree Restricted apt install \\  gstreamer1.0-libav \\  gstreamer1.0-plugins-ugly \\  gstreamer1.0-vaapi \\  intel-microcode \\  libavcodec-extra \\  rar \\  ttf-mscorefonts-installer \\  unrar "});index.add({'id':7,'href':'/note/debian/','title':"Debian",'parent':"Notes",'content':""});index.add({'id':8,'href':'/note/debian/dell-xps-15-9560/','title':"Dell XPS 15 9560",'parent':"Debian",'content':"Installer missing non-free wifi firmware The Intel 8265/8275 requires non-free firmware whoever this can be added to the installation media.\nCopy the non-free firmware-iwlwifi_*_all.deb from https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/ to firmware folder of the installation media.\nACPI issue There is currently a bug that means that some kernels (particularly newer ones) will detect the wrong ACPI revision.\nAdd acpi_rev_override=5 to /etc/default/grub\nGRUB_CMDLINE_LINUX=\u0026#34;acpi_rev_override=5 quiet\u0026#34; Update grub\nupdate-grub Reference    Name Link     Debian XPS 15 9560 https://wiki.debian.org/InstallingDebianOn/Dell/Dell_XPS_15_9560   Non-free firmware https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/    "});index.add({'id':9,'href':'/categories/','title':"Categories",'parent':"Home",'content':""});index.add({'id':10,'href':'/tags/','title':"Tags",'parent':"Home",'content':""});})();